import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"사이버펑크 엣지러너","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/animations/사이버펑크-엣지러너.md","filePath":"outta-space/knowledge/animations/사이버펑크-엣지러너.md"}'),n={name:"outta-space/knowledge/animations/사이버펑크-엣지러너.md"};function i(_,a,l,s,p,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="사이버펑크-엣지러너" tabindex="-1">사이버펑크 엣지러너 <a class="header-anchor" href="#사이버펑크-엣지러너" aria-label="Permalink to &quot;사이버펑크 엣지러너&quot;">​</a></h1><h2 id="_1-이야기와-전개" tabindex="-1">1. 이야기와 전개 <a class="header-anchor" href="#_1-이야기와-전개" aria-label="Permalink to &quot;1. 이야기와 전개&quot;">​</a></h2><p>디지털 세상과 사이버펑크 사회에 갈려나가는 인물들의 이야기다.</p><p>꿈도 희망도 거의 없는 세계관 속에서 인물들이 조금씩 망가져 가는 과정이 중심이다. 떡밥과 복선이 많아서 찾아보는 재미가 있고, 인물의 성장과 피폐화를 보는 맛도 있다.</p><h2 id="_2-캐릭터와-감정선" tabindex="-1">2. 캐릭터와 감정선 <a class="header-anchor" href="#_2-캐릭터와-감정선" aria-label="Permalink to &quot;2. 캐릭터와 감정선&quot;">​</a></h2><p>데이비드가 왜 자신의 전부를 바치고 싶어 했는지, 그리고 그 선택이 어떤 감정에서 나왔는지는 궁금하게 남는다.</p><p>루시와의 관계, 팀과의 유대, 나이트시티라는 환경이 데이비드를 어떻게 몰아붙였는지는 이해되지만, 후반부의 감정 변화는 더 설명이 있었으면 좋았을 것 같다.</p><h2 id="_3-작화와-영상미" tabindex="-1">3. 작화와 영상미 <a class="header-anchor" href="#_3-작화와-영상미" aria-label="Permalink to &quot;3. 작화와 영상미&quot;">​</a></h2><p>사이버펑크 특유의 색감, 속도감, 폭력성이 강하다. 세계관의 과밀함과 피로감이 시각적으로 잘 표현된다.</p><h2 id="_4-음악과-성우-연기" tabindex="-1">4. 음악과 성우 연기 <a class="header-anchor" href="#_4-음악과-성우-연기" aria-label="Permalink to &quot;4. 음악과 성우 연기&quot;">​</a></h2><p>음악과 연출은 작품의 장점이다. 사이버펑크 세계의 질주감과 인물들의 파국을 강하게 밀어붙인다.</p><p>너를 달에 데려다 줄게!!!!</p><h2 id="_5-주제와-여운" tabindex="-1">5. 주제와 여운 <a class="header-anchor" href="#_5-주제와-여운" aria-label="Permalink to &quot;5. 주제와 여운&quot;">​</a></h2><p>디지털 세상에서 인간이 어떻게 소모되는지를 보여준다. 복선과 피폐함의 농도는 좋았지만, 마지막 화는 아쉬움이 남았다.</p><p>특히 잭스의 추상화 연출과 과거 회상이 기대만큼 감정적으로 회수되지 않았고, 케인이 갑자기 단원들을 도와주는 전개도 설명이 부족했다. 결말 역시 현실의 자신을 복제한 AI라는 사실을 알게 된 뒤 디지털 세상에서 잘 사는 것이 목표가 되어버린 듯해, 이전까지의 목표와 어긋나는 느낌이 있었다.</p><p>한 줄 평: 복선과 피폐함은 강렬하지만, 마지막 회의 연출과 결말 처리에서 힘이 빠진 사이버펑크 애니메이션.</p>',16)])])}const u=e(n,[["render",i]]);export{c as __pageData,u as default};
